import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { SafeAreaView, View, Text, Pressable, ActivityIndicator, StyleSheet, ScrollView, Alert } from "react-native";
import * as AuthSession from "expo-auth-session";
import * as WebBrowser from "expo-web-browser";
import * as SecureStore from "expo-secure-store";

WebBrowser.maybeCompleteAuthSession();

const OAUTH = {
  issuer: "https://example.com",
  authorizationEndpoint: "https://example.com/oauth/authorize",
  tokenEndpoint: "https://example.com/oauth/token",
  revocationEndpoint: "https://example.com/oauth/revoke",
  userInfoEndpoint: "https://example.com/oauth/userinfo",
  redirectUri: AuthSession.makeRedirectUri({ useProxy: true }),
  scopes: ["openid", "profile", "email", "offline_access"],
  // IMPORTANT: Do NOT embed client_secret in a mobile app. Use PKCE + public client.
  clientId: "mobile_app_client_123",
};

const STORAGE_KEYS = {
  token: "oauth_token",
};

function nowSeconds() {
  return Math.floor(Date.now() / 1000);
}

function isExpired(token) {
  if (!token?.expiresAt) return true;
  return token.expiresAt <= nowSeconds() + 30;
}

async function saveToken(token) {
  await SecureStore.setItemAsync(STORAGE_KEYS.token, JSON.stringify(token));
}

async function loadToken() {
  const raw = await SecureStore.getItemAsync(STORAGE_KEYS.token);
  return raw ? JSON.parse(raw) : null;
}

async function clearToken() {
  await SecureStore.deleteItemAsync(STORAGE_KEYS.token);
}

async function fetchJson(url, options) {
  const res = await fetch(url, options);
  const text = await res.text();
  let json;
  try {
    json = text ? JSON.parse(text) : {};
  } catch {
    json = { raw: text };
  }
  if (!res.ok) {
    const err = new Error(`HTTP ${res.status}`);
    err.status = res.status;
    err.body = json;
    throw err;
  }
  return json;
}

function toFormUrlEncoded(obj) {
  const params = new URLSearchParams();
  Object.entries(obj).forEach(([k, v]) => {
    if (v === undefined || v === null) return;
    params.append(k, String(v));
  });
  return params.toString();
}

async function exchangeCodeForToken({ code, codeVerifier, redirectUri }) {
  const body = toFormUrlEncoded({
    grant_type: "authorization_code",
    client_id: OAUTH.clientId,
    code,
    redirect_uri: redirectUri,
    code_verifier: codeVerifier,
  });

  const json = await fetchJson(OAUTH.tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      Accept: "application/json",
    },
    body,
  });

  const expiresIn = Number(json.expires_in || 3600);
  return {
    accessToken: json.access_token,
    refreshToken: json.refresh_token,
    idToken: json.id_token,
    tokenType: json.token_type || "Bearer",
    scope: json.scope,
    expiresAt: nowSeconds() + expiresIn,
  };
}

async function refreshAccessToken(refreshToken) {
  const body = toFormUrlEncoded({
    grant_type: "refresh_token",
    client_id: OAUTH.clientId,
    refresh_token: refreshToken,
  });

  const json = await fetchJson(OAUTH.tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      Accept: "application/json",
    },
    body,
  });

  const expiresIn = Number(json.expires_in || 3600);
  return {
    accessToken: json.access_token,
    refreshToken: json.refresh_token || refreshToken,
    idToken: json.id_token,
    tokenType: json.token_type || "Bearer",
    scope: json.scope,
    expiresAt: nowSeconds() + expiresIn,
  };
}

async function revokeToken(token) {
  if (!token) return;
  const body = toFormUrlEncoded({
    token,
    client_id: OAUTH.clientId,
  });

  try {
    await fetchJson(OAUTH.revocationEndpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
        Accept: "application/json",
      },
      body,
    });
  } catch {
    // ignore
  }
}

async function getUserInfo(accessToken) {
  return fetchJson(OAUTH.userInfoEndpoint, {
    method: "GET",
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: "application/json",
    },
  });
}

export default function App() {
  const [token, setToken] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState(null);

  const discovery = useMemo(
    () => ({
      authorizationEndpoint: OAUTH.authorizationEndpoint,
      tokenEndpoint: OAUTH.tokenEndpoint,
      revocationEndpoint: OAUTH.revocationEndpoint,
    }),
    []
  );

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH.clientId,
      redirectUri: OAUTH.redirectUri,
      scopes: OAUTH.scopes,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
    },
    discovery
  );

  const mountedRef = useRef(true);
  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
    };
  }, []);

  const load = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const t = await loadToken();
      if (!mountedRef.current) return;
      setToken(t);
    } catch (e) {
      setError(e);
    } finally {
      setBusy(false);
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const ensureFreshToken = useCallback(async () => {
    const current = token || (await loadToken());
    if (!current) return null;

    if (!isExpired(current)) return current;

    if (!current.refreshToken) {
      await clearToken();
      if (mountedRef.current) setToken(null);
      return null;
    }

    const refreshed = await refreshAccessToken(current.refreshToken);
    await saveToken(refreshed);
    if (mountedRef.current) setToken(refreshed);
    return refreshed;
  }, [token]);

  const handleLogin = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const result = await promptAsync({ useProxy: true, showInRecents: true });
      if (result.type !== "success") return;

      const code = result.params?.code;
      if (!code) throw new Error("Missing authorization code");

      const codeVerifier = request?.codeVerifier;
      if (!codeVerifier) throw new Error("Missing PKCE code_verifier");

      const t = await exchangeCodeForToken({
        code,
        codeVerifier,
        redirectUri: OAUTH.redirectUri,
      });

      await saveToken(t);
      if (!mountedRef.current) return;
      setToken(t);
    } catch (e) {
      setError(e);
      Alert.alert("Login failed", e?.message || "Unknown error");
    } finally {
      setBusy(false);
    }
  }, [promptAsync, request?.codeVerifier]);

  useEffect(() => {
    (async () => {
      if (!token?.accessToken) {
        setUserInfo(null);
        return;
      }
      setBusy(true);
      setError(null);
      try {
        const fresh = await ensureFreshToken();
        if (!fresh?.accessToken) {
          setUserInfo(null);
          return;
        }
        const info = await getUserInfo(fresh.accessToken);
        if (!mountedRef.current) return;
        setUserInfo(info);
      } catch (e) {
        setError(e);
      } finally {
        setBusy(false);
      }
    })();
  }, [token?.accessToken, ensureFreshToken]);

  const handleLogout = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const t = token || (await loadToken());
      if (t?.refreshToken) await revokeToken(t.refreshToken);
      if (t?.accessToken) await revokeToken(t.accessToken);
      await clearToken();
      if (!mountedRef.current) return;
      setToken(null);
      setUserInfo(null);
    } catch (e) {
      setError(e);
    } finally {
      setBusy(false);
    }
  }, [token]);

  const handleCallApi = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const fresh = await ensureFreshToken();
      if (!fresh?.accessToken) {
        Alert.alert("Not logged in", "Please log in first.");
        return;
      }
      const json = await fetchJson("https://example.com/api/me", {
        method: "GET",
        headers: {
          Authorization: `Bearer ${fresh.accessToken}`,
          Accept: "application/json",
        },
      });
      Alert.alert("API response", JSON.stringify(json, null, 2));
    } catch (e) {
      setError(e);
      Alert.alert("API error", e?.message || "Unknown error");
    } finally {
      setBusy(false);
    }
  }, [ensureFreshToken]);

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.header}>
        <Text style={styles.title}>OAuth 2.0 (PKCE) Demo</Text>
        <Text style={styles.sub}>
          Redirect URI: {OAUTH.redirectUri}
        </Text>
      </View>

      <View style={styles.container}>
        <View style={styles.row}>
          <Pressable
            style={[styles.button, (!request || busy) && styles.buttonDisabled]}
            disabled={!request || busy}
            onPress={handleLogin}
          >
            <Text style={styles.buttonText}>{token ? "Re-Login" : "Login"}</Text>
          </Pressable>

          <Pressable
            style={[styles.button, (!token || busy) && styles.buttonDisabled]}
            disabled={!token || busy}
            onPress={handleLogout}
          >
            <Text style={styles.buttonText}>Logout</Text>
          </Pressable>
        </View>

        <Pressable
          style={[styles.buttonWide, (!token || busy) && styles.buttonDisabled]}
          disabled={!token || busy}
          onPress={handleCallApi}
        >
          <Text style={styles.buttonText}>Call Protected API</Text>
        </Pressable>

        {busy ? (
          <View style={styles.busy}>
            <ActivityIndicator />
            <Text style={styles.busyText}>Working…</Text>
          </View>
        ) : null}

        <ScrollView style={styles.card} contentContainerStyle={styles.cardContent}>
          <Text style={styles.sectionTitle}>Session</Text>
          <Text style={styles.mono}>
            {token ? JSON.stringify(token, null, 2) : "Not authenticated"}
          </Text>

          <Text style={styles.sectionTitle}>User Info</Text>
          <Text style={styles.mono}>
            {userInfo ? JSON.stringify(userInfo, null, 2) : "No user info loaded"}
          </Text>

          {error ? (
            <>
              <Text style={styles.sectionTitle}>Error</Text>
              <Text style={styles.mono}>{String(error?.message || error)}</Text>
            </>
          ) : null}
        </ScrollView>
      </View>

      <View style={styles.footer}>
        <Text style={styles.footerText}>
          Configure endpoints in OAUTH.* to match your provider.
        </Text>
      </View>
    </SafeAreaView>
  );
}

